class TextEditor {
    String text;
    int cursorPos;

    public TextEditor() {
        text = "";
        cursorPos = 0;
    }

    public void addText(String text) {
        this.text += text;
        cursorPos += text.length();
    }

    public int deleteText(int k) {
        int cursorPosBefore = cursorPos;
        cursorPos -= k;
        return cursorPosBefore - cursorPos;
    }

    public String cursorLeft(int k) {
        int cursorPosBefore = cursorPos;
        cursorPos -= k;
        return text.substring(cursorPos, cursorPos + k);
    }

    public String cursorRight(int k) {
        int cursorPosBefore = cursorPos;
        cursorPos += k;
        return text.substring(cursorPos - k, cursorPos);
    }
}
```

